using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Load data
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" → true/false for the Label column
var labelLookup = mlContext.Data.LoadFromEnumerable(new[]
{
    new LabelLookup { Churned = "Yes", Label = true },
    new LabelLookup { Churned = "No",  Label = false },
});

// Build pipeline: map label, encode Region, concatenate features, train
var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", labelLookup, labelLookup.Schema["Churned"], labelLookup.Schema["Label"], "Churned")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree());

// Split and evaluate when there is enough data; otherwise train on everything
var rowCount = (int)mlContext.Data.CreateEnumerable<CustomerData>(dataView, reuseRowObject: false).Count();
ITransformer model;
if (rowCount >= 20)
{
    var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);
    model = pipeline.Fit(split.TrainSet);
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
else
{
    Console.WriteLine($"Dataset has only {rowCount} rows — training on all data (no held-out evaluation).");
    model = pipeline.Fit(dataView);
}

// Save model and register pooled prediction engine
mlContext.Model.Save(model, dataView.Schema, modelPath);
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var result = pool.Predict(input);

    return Results.Ok(new
    {
        willChurn = result.WillChurn,
        probability = Math.Round(result.Probability, 4),
        score = Math.Round(result.Score, 4)
    });
});

app.Run();

